function toMillis(v) {
  if (!v) return null;
  const d = new Date(v);
  const t = d.getTime();
  return Number.isNaN(t) ? null : t;
}

function isNetherlands(location) {
  const text = String(location || '').toLowerCase();
  const keys = ['netherlands', 'nederland', 'nl', 'amsterdam', 'rotterdam', 'utrecht', 'den haag', 'the hague', 'eindhoven'];
  return keys.some(k => text.includes(k));
}

const now = Date.now();
const sevenDaysAgo = now - (7 * 24 * 60 * 60 * 1000);

const out = [];
for (const item of items) {
  const src = item.json || {};
  const rawTitle = src.title || '';
  const applyUrl = src.link || '';
  const dateRaw = src.isoDate || src.pubDate || null;
  const dateMs = toMillis(dateRaw);

  const parts = String(rawTitle).split(' - ').map(p => p.trim()).filter(Boolean);
  let title = rawTitle;
  let company = '';
  let location = '';
  if (parts.length >= 3) {
    title = parts[0];
    company = parts[1];
    location = parts.slice(2).join(' - ');
  } else if (parts.length === 2) {
    title = parts[0];
    company = parts[1];
  }

  const description = src.contentSnippet || src.content || src.summary || '';

  if (!applyUrl) continue;
  if (!dateMs) continue;
  if (dateMs < sevenDaysAgo || dateMs > now + 24 * 60 * 60 * 1000) continue;
  if (!isNetherlands(location)) continue;

  out.push({
    json: {
      title,
      company,
      location,
      datePosted: new Date(dateMs).toISOString(),
      applyUrl,
      descriptionSnippet: String(description).replace(/\s+/g, ' ').trim(),
      source: 'indeed_nl_rss'
    }
  });
}

return out;
